// TG-118: Build HTML Email from structured report data
// Input: { report_title, report_subtitle, sections: [ { type, ... } ] }
// Section types: metrics, highlights, table, anomalies, actions

const input = $input.first().json;
const title = input.report_title || 'Weekly Report';
const subtitle = input.report_subtitle || '';
const sections = input.sections || [];
const now = new Date().toISOString().split('T')[0];

// --- Color palette ---
const DARK_GREEN = '#1a5d1a';
const LIGHT_GREEN = '#e8f5e9';
const GREEN_TEXT = '#2e7d32';
const RED_TEXT = '#c62828';
const ORANGE_BG = '#fff3e0';
const ORANGE_BORDER = '#e65100';
const RED_BG = '#fbe9e7';
const RED_BORDER = '#c62828';
const GRAY_BG = '#f5f5f5';
const BORDER_COLOR = '#e0e0e0';
const TEXT_PRIMARY = '#212121';
const TEXT_SECONDARY = '#616161';

// --- Section renderers ---

function renderMetrics(section) {
  const items = section.items || [];
  if (items.length === 0) return '';
  const cards = items.map(m => {
    const changeColor = (m.change || '').toString().startsWith('-') ? RED_TEXT : GREEN_TEXT;
    const changeHtml = m.change ? `<div style="font-size:13px;color:${changeColor};font-weight:600;margin-top:4px;">${m.change}</div>` : '';
    return `<td style="padding:8px;text-align:center;vertical-align:top;width:${Math.floor(100/Math.min(items.length,4))}%;">
      <div style="background-color:#ffffff;border:1px solid ${BORDER_COLOR};border-radius:8px;padding:16px 12px;">
        <div style="font-size:12px;color:${TEXT_SECONDARY};text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px;">${m.label || ''}</div>
        <div style="font-size:28px;font-weight:700;color:${TEXT_PRIMARY};line-height:1.2;">${m.value || '—'}</div>
        ${changeHtml}
      </div>
    </td>`;
  }).join('');
  // Wrap in rows of 4 max
  const rows = [];
  for (let i = 0; i < items.length; i += 4) {
    rows.push(cards.slice(i, i + 4).join(''));
  }
  const sectionTitle = section.title ? `<tr><td colspan="4" style="padding:24px 0 8px 0;font-size:18px;font-weight:700;color:${TEXT_PRIMARY};">${section.title}</td></tr>` : '';
  return `${sectionTitle}${rows.map(r => `<tr>${r}</tr>`).join('')}`;
}

function renderHighlights(section) {
  const items = section.items || [];
  if (items.length === 0) return '';
  const sectionTitle = section.title || 'Highlights';
  const bullets = items.map(h => 
    `<tr><td style="padding:6px 0 6px 0;">
      <div style="border-left:4px solid ${GREEN_TEXT};padding:8px 12px;background-color:${LIGHT_GREEN};border-radius:0 4px 4px 0;font-size:14px;color:${TEXT_PRIMARY};line-height:1.5;">${h}</div>
    </td></tr>`
  ).join('');
  return `<tr><td style="padding:24px 0 8px 0;font-size:18px;font-weight:700;color:${TEXT_PRIMARY};">${sectionTitle}</td></tr>${bullets}`;
}

function renderTable(section) {
  const headers = section.headers || [];
  const rows = section.rows || [];
  if (headers.length === 0 && rows.length === 0) return '';
  const sectionTitle = section.title || 'Data';
  const headerCells = headers.map((h, i) => 
    `<th style="padding:10px 12px;text-align:${i === 0 ? 'left' : 'right'};font-size:12px;text-transform:uppercase;letter-spacing:0.5px;color:${TEXT_SECONDARY};border-bottom:2px solid ${BORDER_COLOR};background-color:${GRAY_BG};">${h}</th>`
  ).join('');
  const dataRows = rows.map((row, ri) => {
    const bgColor = ri % 2 === 0 ? '#ffffff' : GRAY_BG;
    const cells = row.map((cell, ci) => 
      `<td style="padding:10px 12px;text-align:${ci === 0 ? 'left' : 'right'};font-size:14px;color:${TEXT_PRIMARY};border-bottom:1px solid ${BORDER_COLOR};background-color:${bgColor};">${cell}</td>`
    ).join('');
    return `<tr>${cells}</tr>`;
  }).join('');
  return `<tr><td style="padding:24px 0 8px 0;font-size:18px;font-weight:700;color:${TEXT_PRIMARY};">${sectionTitle}</td></tr>
    <tr><td style="padding:0;">
      <table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid ${BORDER_COLOR};border-radius:8px;border-collapse:collapse;">
        <tr>${headerCells}</tr>
        ${dataRows}
      </table>
    </td></tr>`;
}

function renderAnomalies(section) {
  const items = section.items || [];
  if (items.length === 0) return '';
  const sectionTitle = section.title || 'Anomalies Detected';
  const alerts = items.map(a => {
    const severity = (a.severity || 'warning').toLowerCase();
    const bgColor = severity === 'critical' ? RED_BG : ORANGE_BG;
    const borderColor = severity === 'critical' ? RED_BORDER : ORANGE_BORDER;
    const label = typeof a === 'string' ? a : (a.message || a.description || JSON.stringify(a));
    const severityBadge = typeof a !== 'string' && a.severity ? `<span style="display:inline-block;font-size:11px;font-weight:700;text-transform:uppercase;color:#ffffff;background-color:${borderColor};padding:2px 8px;border-radius:3px;margin-right:8px;">${a.severity}</span>` : '';
    return `<tr><td style="padding:6px 0;">
      <div style="border-left:4px solid ${borderColor};padding:10px 12px;background-color:${bgColor};border-radius:0 4px 4px 0;font-size:14px;color:${TEXT_PRIMARY};line-height:1.5;">${severityBadge}${label}</div>
    </td></tr>`;
  }).join('');
  return `<tr><td style="padding:24px 0 8px 0;font-size:18px;font-weight:700;color:${TEXT_PRIMARY};">${sectionTitle}</td></tr>${alerts}`;
}

function renderActions(section) {
  const items = section.items || [];
  if (items.length === 0) return '';
  const sectionTitle = section.title || 'Recommended Actions';
  const numbered = items.map((a, i) => 
    `<tr><td style="padding:4px 0;">
      <div style="padding:8px 12px;font-size:14px;color:${TEXT_PRIMARY};line-height:1.5;">
        <span style="display:inline-block;width:24px;height:24px;background-color:${DARK_GREEN};color:#ffffff;border-radius:50%;text-align:center;line-height:24px;font-size:12px;font-weight:700;margin-right:10px;vertical-align:middle;">${i+1}</span>${a}
      </div>
    </td></tr>`
  ).join('');
  return `<tr><td style="padding:24px 0 8px 0;font-size:18px;font-weight:700;color:${TEXT_PRIMARY};">${sectionTitle}</td></tr>${numbered}`;
}

// --- Assemble HTML ---

let bodyHtml = '';
for (const section of sections) {
  switch (section.type) {
    case 'metrics':    bodyHtml += renderMetrics(section); break;
    case 'highlights': bodyHtml += renderHighlights(section); break;
    case 'table':      bodyHtml += renderTable(section); break;
    case 'anomalies':  bodyHtml += renderAnomalies(section); break;
    case 'actions':    bodyHtml += renderActions(section); break;
    default: break; // skip unknown types gracefully
  }
}

const subtitleHtml = subtitle ? `<div style="font-size:14px;color:rgba(255,255,255,0.85);margin-top:4px;">${subtitle}</div>` : '';

const html = `<!DOCTYPE html>
<html lang="en">
<head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head>
<body style="margin:0;padding:0;background-color:#f0f0f0;font-family:Arial,Helvetica,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f0f0f0;padding:24px 0;">
    <tr><td align="center">
      <table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background-color:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);">
        <!-- Header -->
        <tr><td style="background-color:${DARK_GREEN};padding:28px 32px;">
          <div style="font-size:24px;font-weight:700;color:#ffffff;line-height:1.3;">${title}</div>
          ${subtitleHtml}
        </td></tr>
        <!-- Body -->
        <tr><td style="padding:8px 32px 32px 32px;">
          <table width="100%" cellpadding="0" cellspacing="0">
            ${bodyHtml}
          </table>
        </td></tr>
        <!-- Footer -->
        <tr><td style="background-color:${GRAY_BG};padding:20px 32px;border-top:1px solid ${BORDER_COLOR};">
          <div style="font-size:12px;color:${TEXT_SECONDARY};text-align:center;line-height:1.6;">
            Generated by TotalGuard Intelligence Layer<br>
            ${now} | tgyardcare.com
          </div>
        </td></tr>
      </table>
    </td></tr>
  </table>
</body>
</html>`;

return [{ json: { html, title, subtitle, section_count: sections.length } }];

// Return final HTML + plain text version
const input = $input.first().json;
const html = input.html || '';

// Strip HTML tags for plain text fallback
const plain_text = html
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/tr>/gi, '\n')
  .replace(/<\/td>/gi, ' | ')
  .replace(/<\/div>/gi, '\n')
  .replace(/<\/p>/gi, '\n\n')
  .replace(/<[^>]+>/g, '')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

return [{ json: { html, plain_text } }];
